        ds_resultsCopinoOut.setCellData(0, "doNo", ed_doNo1.getValue());
        // 입항년도
        ds_resultsCopinoOut.setCellData(0, "vsslArrvlportYr", ica_vsslArrvlportYr1.getValue());
        // 화주
        ds_resultsCopinoOut.setCellData(0, "mchtCd", ed_mchtCd1.getValue());
        // 연락처
        ds_resultsCopinoOut.setCellData(0, "cntctPl", ed_tel1.getValue());

        // 특이사항
        ds_resultsCopinoOut.setCellData(0, "rmk", ed_rmk1.getValue());
        // 보세장치장
        ds_resultsCopinoOut.setCellData(0, "bondYardCd", ed_bondYardCd.getValue());
        ds_resultsCopinoOut.setCellData(0, "vehclCls", acb_vehclCls1.getValue());
        ds_resultsCopinoOut.setCellData(0, "bondTransVehclYn", acb_bondTransVehclYn1.getValue());
        ds_resultsCopinoOut.setCellData(0, "chassisPosInfo", acb_chassisPosInfo1.getValue());
        ds_resultsCopinoOut.setCellData(0, "fullEmptyClsCd", acb_fullEmptyClsCd1.getValue());
