        ds_resultsCopinoOut.setCellData(0, "selfCls", acb_selfCls1.getValue());
        ds_resultsCopinoOut.setCellData(0, "xrayRettlPassYn", cbx_xrayRettlPassYn1.getValue());
        ds_resultsCopinoOut.setCellData(0, "bondTransYn", cbx_out_bondTransYn.getValue());
        ds_resultsCopinoOut.setCellData(0, "mchtNm", ed_bondYardNm.getValue());

        var crryinoutDtmMint1  = ica_crryinoutDt1.getValue() + ed_crryinoutHh1.getValue();
        ds_resultsCopinoOut.setCellData(0, "crryinoutDtmMint", crryinoutDtmMint1);

    };

    if(cbx_crryInCopino.getValue() == "1"){

        ds_resultsCopinoIn.setCellData(0, "transDstFrom", ed_transDstFrom2.getValue());
        ds_resultsCopinoIn.setCellData(0, "transDstFromNm", ed_transDstFromNm2.getValue());
        ds_resultsCopinoIn.setCellData(0, "transDstTo", ed_transDstTo2.getValue());
        ds_resultsCopinoIn.setCellData(0, "transDstToNm", ed_transDstToNm2.getValue());
        ds_resultsCopinoIn.setCellData(0, "cntrNo", ed_cntrNo2.getValue());
        ds_resultsCopinoIn.setCellData(0, "vehclNoFrtcarNo", ed_vehclNoFrtcarNo2.getValue());
        ds_resultsCopinoIn.setCellData(0, "vehclNoFull", ed_vehclNoFull2.getValue());
        ds_resultsCopinoIn.setCellData(0, "transCoCd", ed_transCoCd2.getValue());
        ds_resultsCopinoIn.setCellData(0, "suitCoTransCoNm", ed_suitCoTransCoNm2.getValue());
        ds_resultsCopinoIn.setCellData(0, "chassisNo", ed_chassisNo2.getValue());
        ds_resultsCopinoIn.setCellData(0, "sizTyp", ed_sizTyp2.getValue());
        ds_resultsCopinoIn.setCellData(0, "frzTemper", ed_frzTemper2.getValue());
        ds_resultsCopinoIn.setCellData(0, "dangerCd", ed_dangerCd2.getValue());
        ds_resultsCopinoIn.setCellData(0, "totWt", ed_totWt2.getValue());
        ds_resultsCopinoIn.setCellData(0, "overLength", ed_overLength2.getValue());
        ds_resultsCopinoIn.setCellData(0, "overWidth", ed_overWidth2.getValue());
        ds_resultsCopinoIn.setCellData(0, "overHeight", ed_overHeight2.getValue());
        ds_resultsCopinoIn.setCellData(0, "sealNo", ed_sealNo2.getValue());
        ds_resultsCopinoIn.setCellData(0, "shpCoCd", ed_shpCoCd2.getValue());
        ds_resultsCopinoIn.setCellData(0, "tmlVsslPortcnt", ed_tmlVsslPortcnt2.getValue());
        ds_resultsCopinoIn.setCellData(0, "dchrPort", ed_dchrPort2.getValue());
        ds_resultsCopinoIn.setCellData(0, "dchrPortNm", ed_dchrPortNm2.getValue());
        ds_resultsCopinoIn.setCellData(0, "blNo", ed_blNo2.getValue());
        ds_resultsCopinoIn.setCellData(0, "bookingNo", ed_bookingNo2.getValue());
        ds_resultsCopinoIn.setCellData(0, "admitNo", ed_admitNo2.getValue());
        ds_resultsCopinoIn.setCellData(0, "doNo", ed_doNo2.getValue());
        ds_resultsCopinoIn.setCellData(0, "vsslArrvlportYr", ica_vsslArrvlportYr2.getValue());
        ds_resultsCopinoIn.setCellData(0, "mchtCd", ed_mchtCd2.getValue());
        ds_resultsCopinoIn.setCellData(0, "iccntctPic", em_ctaNm.getValue());
        ds_resultsCopinoIn.setCellData(0, "iccntctPl", em_ctaTel.getValue());
        ds_resultsCopinoIn.setCellData(0, "cntctPl", ed_tel2.getValue());
        ds_resultsCopinoIn.setCellData(0, "rmk", ed_rmk2.getValue());
        ds_resultsCopinoIn.setCellData(0, "vehclCls", acb_vehclCls2.getValue());
        ds_resultsCopinoIn.setCellData(0, "bondTransVehclYn", acb_bondTransVehclYn2.getValue());
        ds_resultsCopinoIn.setCellData(0, "chassisPosInfo", acb_chassisPosInfo2.getValue());
        ds_resultsCopinoIn.setCellData(0, "fullEmptyClsCd", acb_fullEmptyClsCd2.getValue());
        ds_resultsCopinoIn.setCellData(0, "expimpClsCd", acb_expimpClsCd2.getValue());
        ds_resultsCopinoIn.setCellData(0, "temperCls", acb_temperCls2.getValue());
        ds_resultsCopinoIn.setCellData(0, "dangerCls", acb_dangerCls2.getValue());
        ds_resultsCopinoIn.setCellData(0, "tsCls", acb_tsCls2.getValue());
        ds_resultsCopinoIn.setCellData(0, "selfCls", acb_selfCls2.getValue());
        ds_resultsCopinoIn.setCellData(0, "bondTransYn", cbx_in_bondTransYn.getValue());

        var crryinoutDtmMint2  = ica_crryinoutDt2.getValue() + ed_crryinoutHh2.getValue();
        ds_resultsCopinoIn.setCellData(0, "crryinoutDtmMint", crryinoutDtmMint2);

    };
    //반출
    if (ds_resultsCopinoOut2.getRowCount() > 0 ) {

        // 구분 : 터미널(T), DPCT(Operator Code :OOL 제외)/ DKCT (D), 부산진(J), LG(L), 경인ICD(당사/고려/천일/현대 등등 : K), 한진자가 ()
        if ( $c.gus.cfIsNull(ds_resultsCopinoOut2.getCellData(0, "cls")) ){
            ds_resultsCopinoOut2.setCellData(0, "cls", "T");	// 구분 : 터미널(T)
        }

        // 송신자 설정
        if ( $c.gus.cfIsNull(ds_resultsCopinoOut2.getCellData(0, "snd")) ){
            ds_resultsCopinoOut2.setCellData(0, "snd", "DBE");	// 송신자 : DEB
        }

        // 수신자 : 각 터미널, DPCT/DKCT 는 작업장 코드, 경인ICD는 "ICD", LG전자는 "LGE"
        if ( $c.gus.cfIsNull(ds_resultsCopinoOut2.getCellData(0, "rcv")) ){
            ds_resultsCopinoOut2.setCellData(0, "rcv", "DBE");	// 송신자 : DEB
        }

        // EDI전송구분 : 전송대기(0)
        if ( $c.gus.cfIsNull(ds_resultsCopinoOut2.getCellData(0, "sndClsCd")) ){
            ds_resultsCopinoOut2.setCellData(0, "sndClsCd" , DsConstants.EDI_SND_CLS_CD_SND_WAIT);	// EDI전송구분 : 전송대기(0)
        }

        //전송구분코드 : 전송(0) 추후전송(3)
        if (ds_resultsCopinoOut2.getCellData(0, "docStsCls") == "") {
            //문서상태코드 : 원본(9) 수정본(4) 삭제본(3)
            ds_resultsCopinoOut2.setCellData(0, "docStsCls", DsConstants.EDI_DOC_STS_CLS_ORIG);
        }
        if ( ds_resultsCopinoOut2.getCellData(0, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_COMPLETE ) {
            ds_resultsCopinoOut2.setCellData(0, "docStsCls", DsConstants.EDI_DOC_STS_CLS_CHG);
        }

        // 반출일시분 설정
        hid_comp.set("hid_crryinoutDtmMint1", ica_crryinoutDt1.getValue() + ed_crryinoutHh1.getValue());

        //ds_resultsCopinoOut2.setGauceJobType(2);
        ds_resultsCopinoOut2.setCellData(0, "setGauceJobType", "2");
        ds_resultsCopinoOut2.setCellData(0, "emcTransCoId", "DBEXC050");
        ds_resultsCopinoOut2.setCellData(0, "dpctTransCoId", "DBEXC050");	    
    };

    //반입
    if (ds_resultsCopinoIn2.getRowCount() > 0 ) {

        // 송신자 설정
        if ( $c.gus.cfIsNull(ds_resultsCopinoIn2.getCellData(0, "snd")) ){
            ds_resultsCopinoIn2.setCellData(0, "snd", "DBE");	// 송신자 : DEB
        }

        // EDI전송구분 : 전송대기(0)
        if ( $c.gus.cfIsNull(ds_resultsCopinoIn2.getCellData(0, "sndClsCd")) ){
            ds_resultsCopinoIn2.setCellData(0, "sndClsCd", DsConstants.EDI_SND_CLS_CD_SND_WAIT);	// EDI전송구분 : 전송대기(0)
        }

        //전송구분코드 : 전송(0) 추후전송(3)
        if (ds_resultsCopinoIn2.getCellData(0, "docStsCls") == "") {
            //문서상태코드 : 원본(9) 수정본(4) 삭제본(3)
            ds_resultsCopinoIn2.setCellData(0, "docStsCls", DsConstants.EDI_DOC_STS_CLS_ORIG);
        }
        if ( ds_resultsCopinoIn2.getCellData(0, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_COMPLETE ) {
            ds_resultsCopinoIn2.setCellData(1, "docStsCls", DsConstants.EDI_DOC_STS_CLS_CHG);
        }

        if (ds_resultsCopinoIn2.getCellData(0, "temperCls") != "") {
            if ( ed_frzTemper2.getValue() == null || ed_frzTemper2.getValue() == "" ) {
                ds_resultsCopinoIn2.setCellData(0, "temperCls", DsConstants.EDI_TEMPER_CLS_DRY);
            } else {
                ds_resultsCopinoIn2.setCellData(0, "temperCls", DsConstants.EDI_TEMPER_CLS_CEL);
            }
        } else {
            ds_resultsCopinoIn2.setCellData(0, "temperCls", "");
        }

        // 반입일시분 설정
        hid_comp.set("hid_crryinoutDtmMint2", ica_crryinoutDt2.getValue() + ed_crryinoutHh2.getValue())

        ds_resultsCopinoIn2.setCellData(0, "setGauceJobType", "2");
        //ds_resultsCopinoIn2.setGauceJobType(2);
        ds_resultsCopinoIn2.setCellData(0, "emcTransCoId", "DBEXC050");
        ds_resultsCopinoIn2.setCellData(0, "dpctTransCoId", "DBEXC050");				
    };
    hid_comp.set("hid_crryinoutDtmMint2", ica_crryinoutDt2.getValue() + ed_crryinoutHh2.getValue());

    //check digit

    if(cbx_crryOutCopino.getValue() == "1"){
        if(!$c.gus.cfIsNull(ed_cntrNo1.getValue()) && ed_cntrNo1.getValue() != ""){
            if( !dscommon.cf_CheckCntrNo(ed_cntrNo1.getValue()) ){
                $c.gus.cfAlertMsg("유효한 컨테이너번호가 아닙니다"); //유효한 @가 아닙니다
            }
        }
    }
    if(cbx_crryInCopino.getValue() == "1"){
        if(!$c.gus.cfIsNull(ed_cntrNo2.getValue()) && ed_cntrNo2.getValue() != ""){
            if( !dscommon.cf_CheckCntrNo(ed_cntrNo2.getValue()) ){
                $c.gus.cfAlertMsg("유효한 컨테이너번호가 아닙니다"); //유효한 @가 아닙니다
            }
        }
    }

    if ((cbx_crryInCopino.getValue() == "0") && (cbx_crryOutCopino.getValue() == "0")){
        $c.gus.cfAlertMsg("저장할 데이터가 없습니다.");
    }else{
        var rtn = await $c.win.confirm("저장하시겠습니까?");
        if (rtn) {
              $c.sbm.execute(sbm_save)
        } else {

        }
    }

};

