scwin.sbm_retrieve_submitDone = function(){

    if( ds_resultsCopinoOut.getRowCount() == 0 ){
		$c.gus.cfAlertMsg(MSG_CM_WRN_002);
		return flase;
  	}
	for (var i = 0; i <= ds_resultsCopinoOut.getRowCount(); i++) {
		//반출
		ed_sndDtHh1.setValue((ds_resultsCopinoOut.getCellData(0, "sndDt") == "" ? "" : $c.gus.cfGetFormatStr(ds_resultsCopinoOut.getCellData(0, "sndDt"), "####/##/##"))
											+ " " + (ds_resultsCopinoOut.getCellData(0, "sndHh") == "" ? "" :  $c.gus.cfGetFormatStr(ds_resultsCopinoOut.getCellData(0, "sndHh"), "##:##:##")));
